-- Migration: Audit & Complete All Australian Visa Records
-- Generated by script

-- 1. Schema Updates
DO $$
BEGIN
    -- Rename subclass_number to subclass if it exists
    IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'visas' AND column_name = 'subclass_number') THEN
        ALTER TABLE public.visas RENAME COLUMN subclass_number TO subclass;
    END IF;

    -- Add missing columns
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'visas' AND column_name = 'cost_aud') THEN
        ALTER TABLE public.visas ADD COLUMN cost_aud TEXT;
    END IF;
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'visas' AND column_name = 'processing_time_range') THEN
        ALTER TABLE public.visas ADD COLUMN processing_time_range TEXT;
    END IF;
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'visas' AND column_name = 'duration') THEN
        ALTER TABLE public.visas ADD COLUMN duration TEXT;
    END IF;
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'visas' AND column_name = 'key_requirements') THEN
        ALTER TABLE public.visas ADD COLUMN key_requirements TEXT;
    END IF;
END $$;

